#include<bits/stdc++.h>
using namespace std;
vector<int> s[500010];
int a[500010],cnt[500010],vis[500010],vis1[500010],id[500010];
int main()
{
    mt19937 rnd(time(0));
    rand();
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        s[a[i]].push_back(i);
    }
    for(int i=1;i<=m;i++)
    {
        int l,r;
        scanf("%d%d",&l,&r);
        int max1=0,ans=0;
        if(r-l+1<=100)
        {
            for(int j=l;j<=r;j++)
            {
                if(vis[a[j]]!=i)
                {
                    vis[a[j]]=i;
                    cnt[a[j]]=0;
                }
                cnt[a[j]]++;
                if(cnt[a[j]]>max1)
                {
                    max1=cnt[a[j]];
                    ans=a[j];
                }
            }
            if(max1*2<=r-l+1)
            {
                printf("0\n");
            }
            else
            {
                printf("%d\n",ans);
            }
            continue;
        }
        int flag=0;
        for(int j=1;j<=50;j++)
        {
            int p=(1ll*rnd()*rnd())%(r-l+1)+l;
            if(vis1[a[p]]==i)
            {
                continue;
            }
            vis1[a[p]]=i;
            if(s[a[p]].size()*2<=r-l+1)
            {
                continue;
            }
            int val=a[p];
            int tmp=lower_bound(s[val].begin(),s[val].end(),l)-s[val].begin();
            int tmp1=(r-l+1)/2;
            if(tmp+tmp1>=s[val].size()||s[val][tmp+tmp1]>r)
            {
                continue;
            }
            flag=1;
            printf("%d\n",val);
            break;
        }
        if(!flag)
        {
            printf("0\n");
        }
    }
    return 0;
}
